def parser(log: str) -> dict[str, str]:
    import re
    results: dict[str, str] = {}
    # Match cargo test lines like: "test module::test_name ... ok|FAILED|ignored"
    pattern = re.compile(r'^\s*test\s+(.+?)\s+\.\.\.\s+(ok|FAILED|ignored)\b', re.IGNORECASE)
    for line in log.splitlines():
        m = pattern.match(line)
        if m:
            name, status = m.groups()
            status_lower = status.lower()
            if status_lower == "ok":
                results[name.strip()] = "pass"
            elif status_lower == "failed":
                results[name.strip()] = "fail"
            elif status_lower == "ignored":
                results[name.strip()] = "skip"
    return results
